parameters.jsonBody:
{
  "operationName": "OrderLineList",
  "variables": {
    "forPurchase": true,
    "first": 20,
    "filter": {
      "orderStatus": ["READY_TO_FULFILL_PLUS_BEING_APPROVED"],
      "orderType": ["BY_STAFF_FOR_BAD_STOCK", "BY_STAFF_FOR_BRAND", "BY_HQ_STAFF_FOR_BRAND", "BY_STAFF_FOR_ETC", "BY_USER"],
      "trackInventory": false,
      "deliveryMethods": ["BY_COURIER"],
      "existPurchaseOrderLine": false,
      "fulfilled": false,
      "isB2b": false
    },
    "sort": {
      "direction": "DESC",
      "field": "NUMBER"
    }
  },
  "query": "fragment OrderLineForPurchaseFragment on OrderLine { id composedIdWithPrefix productName quantityUnfulfilled unitPriceExcludeVat thumbnail { url alt } product { id name category { id name } productType { id name } } variant { id name sku stockQuantity stocks { id quantity warehouse { id name } } } } query OrderLineList($first: Int, $filter: OrderLineFilterInput, $sort: OrderLineSortingInput, $forPurchase: Boolean) { orderLines(first: $first, filter: $filter, sortBy: $sort, forPurchase: $forPurchase) { edges { node { ...OrderLineForPurchaseFragment } } } }"
}
